query getMembers(
  $first: IntMax100
  $channelId: String
  $tagFilters: [TagFilter]
  $after: String
) {
  apiViewer {
    members(first: $first, channelId: $channelId, tagFilters: $tagFilters, after: $after) {
      edges {
        node {
          _id
          externalId
          name
          tags
        }
      }
      pageInfo {
        hasNextPage
        totalCount
        endCursor
      }
    }
  }
}

mutation AddMemberTags($input: ModifyMemberTagsInput!) {
  addMemberTags(input: $input) {
    err_code
    member {
      _id
      externalId
    }
    memberId
    ok
  }
}

query getMemberInfo($channelId: ID, $externalId: ID) {
  apiViewer {
    member(channelId: $channelId, externalId: $externalId) {
      _id
      createdAt
      updatedAt
      channelId
      platform
      tags
      meta
      externalId
      botMeta {
        subscribe
        liveChat
        treeId
        nodeCompositeId
        tree {
          name
        }
        node {
          name
        }
      }
      name
      firstName
      lastName
      gender
      customLocale
      locale
      email
    }
  }
}

query getConversationHistory(
  $channelId: String
  $memberId: String
  $last: IntMax100
  $before: String
  $from: Long
  $to: Long
) {
  apiViewer {
    conversationHistory(
      channelId: $channelId
      memberId: $memberId
      last: $last
      before: $before
      from: $from
      to: $to
    ) {
      edges {
        node {
          _id
          messageEvent
          id
          createdAt
          updatedAt
          sentAt
          readAt
          deliveredAt
          deletedAt
          from
          member {
            name
          }
          memberId
          errors
          failedAt
          platform
          channelId
          tags
          meta
          etag
          isMultipleParty
        }
      }
      pageInfo {
        hasPreviousPage
        startCursor
      }
    }
  }
}
